    vector<vector<long long>> dp(n, vector<long long>(1 << n, 0));

    // Initialize dp with the maximum possible length for each node (1)
    for (long long i = 0; i < n; ++i) {
        dp[i][1 << i] = 1;
    }

    // BFS queue for nodes
    queue<pair<long long, long long>> q;
    for (long long i = 0; i < n; ++i) {
        q.push({i, 1 << i});
