        auto [node, mask] = q.front();
        q.pop();

        // Try to move to each neighbor
        for (long long neighbor : adj[node]) {
            long long new_mask = mask | (1 << neighbor);
            if ((mask & (1 << neighbor)) != 0) continue; // Skip if already visited

            // Check if the current path can form a palindrome
            // The current path is from the start to the current node
            // We need to check if the first and last characters are the same
            // If they are, we can extend the palindrome by 2
