long long solve(long long n, vector<vector<long long>> edges, string label) {
    // Build adjacency list
    vector<vector<long long>> adj(n);
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // Use bitmask to represent visited nodes
    unordered_map<long long, vector<long long>> memo; // memo[bitmask] = max palindrome length

    function<long long(long long, long long, long long, long long)> dfs = [&](long long node, long long mask, long long start, long long end) {
        // If this state has been computed before, return the result
        auto it = memo.find(mask);
        if (it != memo.end()) {
            return it->second;
        }

        // If the path is a palindrome
        if (start == end) {
            return 1;
        }

        long long max_len = 0;

        // Try to extend the path in both directions
        for (auto neighbor : adj[node]) {
            if ((mask & (1 << neighbor)) == 0) {
                // Move to the neighbor
                long long new_mask = mask | (1 << neighbor);
                long long new_start = start;
                long long new_end = end;

                // Check if the current path can form a palindrome
                if (label[node] == label[neighbor]) {
                    // If the start and end characters are the same, we can extend the palindrome
                    new_start = start;
                    new_end = end;
                    max_len = max(max_len, dfs(neighbor, new_mask, new_start, new_end));
                } else {
                    // If the characters are different, we can only extend one side
                    max_len = max(max_len, dfs(neighbor, new_mask, start, end));
                    max_len = max(max_len, dfs(neighbor, new_mask, start, end));
                }
            }
        }

        // If no extension is possible, the maximum palindrome length is 1 (the current node)
        if (max_len == 0) {
            max_len = 1;
        }

        memo[mask] = max_len;
        return max_len;
    };

    long long max_palindrome = 0;

    // Try all starting nodes
    for (long long i = 0; i < n; ++i) {
        long long mask = 1 << i;
        long long start = i;
        long long end = i;
        long long current_len = dfs(i, mask, start, end);
        max_palindrome = max(max_palindrome, current_len);
    }

    return max_palindrome;
}
