#include <bits/stdc++.h>
using namespace std;

long long solve(long long n, vector<vector<long long>> edges, string label) {
    // Build adjacency list
    vector<vector<long long>> adj(n);
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // Memoization to store the maximum palindrome length for a given node and visited set
    unordered_map<long long, long long> memo;

    // Helper function to perform DFS
    function<long long(long long, long long)> dfs = [&](long long node, long long visited) {
        // Check if this state is already computed
        auto key = node * 1000000 + visited;
        if (memo.find(key) != memo.end()) {
            return memo[key];
        }

        // Initialize the maximum palindrome length
        long long max_len = 1; // At least the node itself is a palindrome of length 1

        // Check all neighbors
        for (long long neighbor : adj[node]) {
            // Skip if the neighbor is already visited
            if (visited & (1 << neighbor)) continue;

            // Recursively visit the neighbor
            long long len = dfs(neighbor, visited | (1 << neighbor));

            // Check if the current node's label can form a palindrome with the neighbor's path
            // If the current node's label is the same as the neighbor's label, we can extend the palindrome
            if (label[node] == label[neighbor]) {
                max_len = max(max_len, len + 2);
            } else {
                max_len = max(max_len, len + 1);
            }
        }

        memo[key] = max_len;
        return max_len;
    };

    // Try all starting nodes
    long long result = 1;
    for (long long i = 0; i < n; ++i) {
        result = max(result, dfs(i, 1 << i));
    }

    return result;
}
